#include "Movie.h"#include <iomanip>using namespace std;string Movie::getTitle() const {    return title;}string Movie::getDirector() const {    return director;}vector<string> Movie::getMainActors() const {    return mainActors;}void Movie::setTitle(string title) {    this->title = title;}void Movie::setDirector(string director) {    this->director = director;}void Movie::setMainActors(vector<string> mainActors) {    this->mainActors = mainActors;}void Movie::addMainActor(string actor) {    mainActors.push_back(actor);}void Movie::print(ostream &out) const {    const int LABEL_WIDTH = 15; // "Description" and "Borrowed By" fit cleanly    out << left << setw(LABEL_WIDTH) << "Item Type"   << ": Movie" << endl;    out << left << setw(LABEL_WIDTH) << "Name"        << ": " << getName() << endl;    out << left << setw(LABEL_WIDTH) << "Description" << ": " << getDescription() << endl;    out << left << setw(LABEL_WIDTH) << "ID"          << ": " << getId() << endl;    out << left << setw(LABEL_WIDTH) << "Title"       << ": " << title << endl;    out << left << setw(LABEL_WIDTH) << "Director"    << ": " << director << endl;    out << left << setw(LABEL_WIDTH) << "Main Actors" << ": ";    if (mainActors.empty()) {        out << "None";    }    else {        for (size_t i = 0; i < mainActors.size(); i++) {            out << mainActors[i];            if (i < mainActors.size() - 1) {                out << ", ";            }        }    }    out << endl;    if (isCheckedOut()) {        out << left << setw(LABEL_WIDTH) << "Status"      << ": Checked Out" << endl;        out << left << setw(LABEL_WIDTH) << "Borrowed By" << ": " << getBorrowName() << endl;        out << left << setw(LABEL_WIDTH) << "Due Date"    << ": " << getDueDate() << endl;    }    else {        out << left << setw(LABEL_WIDTH) << "Status" << ": Available" << endl;    }}